import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.5.意志力使用","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/3.战斗规则/3.5.意志力使用.md","filePath":"1.基础规则/3.战斗规则/3.5.意志力使用.md"}'),_={name:"1.基础规则/3.战斗规则/3.5.意志力使用.md"};function d(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_3-5-意志力使用",tabindex:"-1"},[s("3.5.意志力使用 "),e("a",{class:"header-anchor",href:"#_3-5-意志力使用","aria-label":'Permalink to "3.5.意志力使用"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),o('<h1 id="意志力使用" tabindex="-1">意志力使用 <a class="header-anchor" href="#意志力使用" aria-label="Permalink to &quot;意志力使用&quot;">​</a></h1><p>意志力使用</p><p>调用意志力是轮回者的基础能力之一，其调用上限根据其意志力池的上限决定，意志力池上限为其决心属性等级+沉着属性等级+决心属性附加数*2，意志力的基础用法如下： 1、在进行任何非自然骰的检定进行时都可以以一个自由动作消耗1点意志力，从而获得这次检定上的3DP表现加值，对于一次检定而言（包括多次检定但为连续的一个行动），至多只能如此做一次。<br> 2、当轮回者在回合外受到攻击且以防御进行抵抗时，也可以一个自由动作以消耗1点意志力，从而获得仅对于这次攻击而言的3点士气防御，对于一次攻击而言（包括多次攻击但为连续的一个行动），至多只能如此做一次。<br> 3、当轮回者进行一次移动时，可以自由动作消耗1点意志力，令这次移动的距离提升15米。<br> 4、在战斗轮的突袭轮及第一轮中，若某轮回者被击伤而不保有任何韧性（且该轮回者不是突袭轮的发起者），他可以选择消耗1点意志，不立即死亡，而是在这一轮中不再受到任何伤害，并将韧性降低至0点，直至那一轮结束，结束时，若其仍不拥有任何韧性，则立即死亡，若保有至少1点，则昏迷，且本战斗场景中无法苏醒。<br> 5、每个场景中仅一次，在意志力不空的情况下，当人物将要因伤势而昏迷时，可以消耗1点意志，再支撑一个自己的回合不晕。<br> 6、每个场景中仅一次，人物可以花费1点意志力进行一次强韧豁免，将等同成功数的冲击点数压制到战斗结束后生效。<br> 7、每场景一次，消耗1+X点意志力重骰一次任意非自然骰检定。X为一日内使用此能力的次数。<br> 最后，当人物的意志力归0时，将立刻昏迷直至恢复至1为止，ST可以选择是否使用这一条规则。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(_,[["render",d]]);export{f as __pageData,m as default};
